import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Wallet, ShoppingBag, CreditCard, 
  LayoutDashboard, Plus, TrendingUp, ChevronRight 
} from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0, totalCartoes: 0 });
  const [usuarioNome, setUsuarioNome] = useState('Usuário');

  useEffect(() => {
    async function buscarDados() {
      // 1. Pega o usuário logado
      const { data: { user } } = await supabase.auth.getUser();
      
      if (user) {
        // 2. Busca o nome no perfil (profiles)
        const { data: perfil } = await supabase
          .from('profiles')
          .select('nome, tipo_usuario')
          .eq('id', user.id)
          .single();
        
        if (perfil) {
          setUsuarioNome(perfil.nome.split(' ')[0]); // Pega apenas o primeiro nome
        }

        // 3. Busca estatísticas (ajustado para o usuário logado)
        // Se quiser que o proprietário veja TUDO, remova o .eq('user_id', user.id)
        const { data: compras } = await supabase
          .from('compras')
          .select('valor_total')
          .eq('user_id', user.id); 

        const { data: cartoes } = await supabase
          .from('cartoes')
          .select('id')
          .eq('user_id', user.id);

        if (compras) {
          const soma = compras.reduce((acc, item) => acc + parseFloat(item.valor_total), 0);
          setResumo({ 
            total: soma, 
            quantidade: compras.length,
            totalCartoes: cartoes ? cartoes.length : 0
          });
        }
      }
    }
    buscarDados();
  }, []);

  const theme = {
    primary: '#4361ee',
    dark: '#0f172a',
    textMuted: '#64748b',
    surface: '#ffffff'
  };

  return (
    <div className="fade-in" style={{ padding: '25px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '100px' }}>
      
      {/* HEADER DINIMALISTA */}
      <header style={{ marginBottom: '35px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <span style={{ color: theme.textMuted, fontSize: '0.9rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px' }}>Visão Geral</span>
          <h1 style={{ fontSize: '2rem', margin: '5px 0 0 0', fontWeight: 800, color: theme.dark }}>
            Olá, {usuarioNome} 👋
          </h1>
        </div>
        <div style={{ background: '#e0e7ff', padding: '10px', borderRadius: '15px' }}>
          <TrendingUp color={theme.primary} size={24} />
        </div>
      </header>

      {/* CARD PRINCIPAL (SALDO/GASTO) */}
      <div style={mainCardStyle(theme)}>
        <div style={{ position: 'relative', zIndex: 2 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: 0.7, marginBottom: '10px' }}>
            <Wallet size={18} />
            <span style={{ fontSize: '0.9rem', fontWeight: 500 }}>Seu Gasto Acumulado</span>
          </div>
          <h2 style={{ fontSize: '2.8rem', margin: 0, fontWeight: 800, letterSpacing: '-1px' }}>
            R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h2>
          <div style={{ display: 'flex', gap: '20px', marginTop: '25px' }}>
            <div style={pillStyle}>
              <span style={pillLabel}>Lançamentos</span>
              <span style={{ fontWeight: 700 }}>{resumo.quantidade} itens</span>
            </div>
            <div style={pillStyle}>
              <span style={pillLabel}>Cartões</span>
              <span style={{ fontWeight: 700 }}>{resumo.totalCartoes} ativos</span>
            </div>
          </div>
        </div>
        <div style={decorationStyle(theme)} />
      </div>

      {/* SEÇÃO DE ATALHOS */}
      <h3 style={{ marginBottom: '20px', color: theme.dark, fontWeight: 700, fontSize: '1.2rem' }}>Ações Rápidas</h3>
      
      <div style={gridStyle}>
        <Link to="/dashboard" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<LayoutDashboard size={26} />} 
            label="Dashboard" 
            sub="Análise"
            bg={theme.surface} 
            color={theme.primary} 
          />
        </Link>

        <Link to="/cartoes" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<CreditCard size={26} />} 
            label="Cartões" 
            sub="Limites"
            bg={theme.surface} 
            color="#7209b7" 
          />
        </Link>

        <Link to="/listagem" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<ShoppingBag size={26} />} 
            label="Extrato" 
            sub="Histórico"
            bg={theme.surface} 
            color="#00cc66" 
          />
        </Link>

        <Link to="/lancamento" style={{ textDecoration: 'none' }}>
          <QuickActionCard 
            icon={<Plus size={26} />} 
            label="Novo" 
            sub="Lançar"
            bg={theme.primary} 
            color="#fff" 
            isPrimary
          />
        </Link>
      </div>

      {/* RODAPÉ RÁPIDO */}
      <Link to="/cartoes" style={{ textDecoration: 'none' }}>
        <div style={footerActionStyle(theme)}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <div style={footerIconBox(theme)}>
              <CreditCard size={20} color={theme.primary} />
            </div>
            <div>
              <span style={{ display: 'block', fontSize: '0.9rem', fontWeight: 700, color: theme.dark }}>Gerenciar Métodos</span>
              <span style={{ fontSize: '0.75rem', color: theme.textMuted }}>Configurações de pagamento</span>
            </div>
          </div>
          <ChevronRight size={20} color={theme.textMuted} />
        </div>
      </Link>
    </div>
